import React, { useState, useEffect, useRef } from 'react';
import { Ruler, Camera, Trash2, Save, CheckCircle, ShieldCheck, Loader2 } from 'lucide-react';
import './styles/ProfileSection.css';

const ProfileSection = () => {
  const [formData, setFormData] = useState(null); // Start as null to track loading better
  const [status, setStatus] = useState({ text: '', type: '' });
  const fileInputRef = useRef(null);

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const token = localStorage.getItem('token');
      const res = await fetch('http://localhost:5000/api/profile', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      const data = await res.json();
      console.log("DATA RECEIVED BY REACT:", data);
      
      if (res.ok) {
        // Map the data clearly
        setFormData({
          name: data.name || '',
          height: data.height || '',
          weight: data.weight || '',
          skinTone: data.skinTone || '',
          chest: data.chest || data.bodyMeasurements?.chest || 0,
          waist: data.waist || data.bodyMeasurements?.waist || 0,
          hips: data.hips || data.bodyMeasurements?.hips || 0,
          fullBodyImage: data.fullBodyImage || ''
        });
      }
    } catch (error) {
      console.error("Fetch error:", error);
    }
  };

  const handleInputChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSave = async () => {
    const token = localStorage.getItem('token');
    const res = await fetch('http://localhost:5000/api/profile/update', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
      body: JSON.stringify(formData)
    });
    if (res.ok) {
      setStatus({ text: 'Neural Profile Synchronized!', type: 'success' });
      setTimeout(() => setStatus({ text: '', type: '' }), 3000);
    }
  };

  // If formData is null, we show the loader. This prevents empty boxes from ever rendering.
  if (!formData) return (
    <div className="dash-loader">
      <Loader2 className="spinner" size={40} />
      <p>Syncing Neural Biometrics...</p>
    </div>
  );

  return (
    <div className="profile-container animate-in">
      <header className="profile-header">
        <div className="title-area">
          <h1>Neural <span className="text-gradient">Fit Profile</span></h1>
          <p>Your digital silhouette is synced and ready.</p>
        </div>
        <button className="save-btn" onClick={handleSave}>
          <Save size={18} /> Update Profile
        </button>
      </header>

      {status.text && <div className={`status-msg ${status.type}`}>{status.text}</div>}

      <div className="profile-grid">
        <div className="profile-card photo-card">
          <div className="card-label"><Camera size={16} /> Virtual Model Photo</div>
          <div className="full-body-preview">
            {formData.fullBodyImage ? (
              <>
                <img src={formData.fullBodyImage} alt="Neural Model" />
                <button className="delete-photo-btn" onClick={() => setFormData({...formData, fullBodyImage: ''})}>
                  <Trash2 size={18} />
                </button>
              </>
            ) : (
              <div className="upload-placeholder" onClick={() => fileInputRef.current.click()}>
                <Camera size={40} />
                <span>Upload Full-Body Photo</span>
              </div>
            )}
            <input type="file" hidden ref={fileInputRef} onChange={(e) => {
               const reader = new FileReader();
               reader.onload = () => setFormData({...formData, fullBodyImage: reader.result});
               reader.readAsDataURL(e.target.files[0]);
            }} />
          </div>
        </div>

        {/* This key ensures the section re-renders when data is loaded */}
        <div className="profile-card data-card" key={formData.name}>
          <div className="card-label"><Ruler size={16} /> Live Biometrics</div>
          
          <div className="input-row">
            <div className="input-group">
              <label>Full Name</label>
              <input type="text" name="name" defaultValue={formData.name} onChange={handleInputChange} />
            </div>
            <div className="input-group">
              <label>Skin Tone</label>
              <input type="text" name="skinTone" defaultValue={formData.skinTone} onChange={handleInputChange} />
            </div>
          </div>

          <div className="measure-grid">
            <div className="measure-item">
              <label>Height (cm)</label>
              <input type="number" name="height" defaultValue={formData.height} onChange={handleInputChange} />
            </div>
            <div className="measure-item">
              <label>Weight (kg)</label>
              <input type="number" name="weight" defaultValue={formData.weight} onChange={handleInputChange} />
            </div>
            <div className="measure-item highlight-pink">
              <label>Chest (cm)</label>
              <input type="number" name="chest" defaultValue={formData.chest} onChange={handleInputChange} />
            </div>
            <div className="measure-item highlight-pink">
              <label>Waist (cm)</label>
              <input type="number" name="waist" defaultValue={formData.waist} onChange={handleInputChange} />
            </div>
            <div className="measure-item highlight-pink">
              <label>Hips (cm)</label>
              <input type="number" name="hips" defaultValue={formData.hips} onChange={handleInputChange} />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProfileSection;
